mapper.insert:
INSERT INTO excerpts (
    id, user_id, poem_id, sentence_index, sentence_text, note, created_at, updated_at
) VALUES (
    #{id}, #{userId}, #{poemId}, #{sentenceIndex}, #{sentenceText}, #{note}, #{createdAt}, #{updatedAt}
)

mapper.select:
SELECT e.*,
       p.title AS poem_title,
       p.dynasty AS poem_dynasty,
       p.author AS poem_author,
       p.content AS poem_content,
       p.tags AS poem_tags
FROM excerpts e
LEFT JOIN poems p ON p.id = e.poem_id
WHERE e.user_id = #{userId}
  AND e.poem_id = #{poemId}
  AND e.sentence_index = #{sentenceIndex}
  AND e.sentence_text = #{sentenceText}
LIMIT 1
